&Linha = &PrimeiraLinha
//&Excel.ReadOnly = 1 
&Excel.Open(&CaminhoArquivoXml)
If &Excel.ErrCode <> 0
	msg(&Excel.ErrDescription)
	return
Else
	&Count = 0
	Do While &Fim < 5

		Do 'LimpaCampos'

		&ForProCod = &Excel.Cells(&Linha,&ColunaREFERENCIA).Text
		&ForProCod = &ForProCod.Trim()

		if not &ForProCod.IsEmpty()
			if &ColunaCoDIGOBARRAS > 0
				&ForProGraBar = &Excel.Cells(&Linha,&ColunaCoDIGOBARRAS).Text
			Endif

			if &ColunaDESCRICAO > 0
				&ForProNom = &Excel.Cells(&Linha,&ColunaDESCRICAO).Text
			Endif

			if &ColunaNCM > 0
				&tmpNcmCod = val(&Excel.Cells(&Linha,&ColunaNCM).Text)
			Endif

			if &ColunaVALORUNITARIO > 0
				&tmpPedVlrUnt = &Excel.Cells(&Linha,&ColunaVALORUNITARIO).Number
			Endif

			&PedQtd = &Excel.Cells(&Linha,&ColunaQUANTIDADE).Number

			do 'getProdutoFornecedor'

			//			Do CAse
			//				CAse &IsNotaPropria = 'P'
			//					&ProGraRef = &ForProCod 
			//					do 'GetProduto'
			//				Case &IsNotaPropria = 'T' or &IsNotaPropria.IsEmpty()
			//					do 'getProdutoFornecedor'
			//			EndCAse


			&Count += 1
			New
				tmpNFeCod = &tmpNFeCod
				tmpProForCod = &ForProCod.ToUpper()
				tmpNfeItmCod = &Count
				tmpProRef = &ProGraRef
				tmpProNomERP = &ProNom
				tmpProNom = &ForProNom
				tmpNcmCod = &tmpNcmCod
				//				tmpNcmCEST = &det.prod.CEST
				//				tmpCFOP = &det.prod.CFOP
				tmpProNcmCod = &tmpProNcmCod
				tmpProBar = &tmpProBar 

				//				if &IsNotaPropria = 'T'
				//					RetornaCfopEntrada.call(&EmpCod, &LctCod, &det.prod.CFOP, &tmpEntCFOP) //AINDA NAO SABEMOS O TIPO LANCAMENTO - JDF
				//					tmpEntCFOP = &tmpEntCFOP
				//				Else
				//					tmpEntCFOP = &det.prod.CFOP
				//				Endif

				If &tmpProQtdCmpEmb > 0
					tmpProQtdCmpEmb = &tmpProQtdCmpEmb
				Else
					tmpProQtdCmpEmb = 1
				EndIf

				//				tmpUndTrib = &det.prod.uTrib.ToUpper()
				//				tmpPedVlrUntTrib = val(&det.prod.vUnTrib)
				tmpPedQtdTrib = &PedQtd

				//				tmpUnd = &det.prod.uCom.ToUpper()
				tmpProCod = &ProCod
				tmpProGraCod = &ProGraCod
				tmpPedVlrUnt = &tmpPedVlrUnt
				//				If &det.prod.rastros.Count > 0 
				//					tmpProSolLot = Status_SimNao.Sim
				//				Else
				tmpProSolLot = Status_SimNao.Nao
				//				EndIf

				tmpNfeProBar = &ForProGraBar
				tmpPedVlrTot = &PedQtd * &tmpPedVlrUnt
				tmpPedQtd = &PedQtd
				tmpProVlrFrt = 0//val(&det.prod.vFrete)
				tmpProVlrOut = 0//val(&det.prod.vOutro)
				tmpPedVlrDsc = 0//val(&det.prod.vDesc)



				tmpNfeOriCod.SetEmpty() // = val(&Origem)
				tmpNfeSitCod.SetEmpty() // = &Situacao.Trim()

				tmpProBasVlrIcm.SetEmpty() // = &NfeProBasIcms
				tmpProVlrIcm.SetEmpty() // = &NfeProVlrIcms
				tmpProPerIcm.SetEmpty() // = &NFeProTaxIcms

				tmpProBasVlrIcmSt.SetEmpty() // = &NfeProBasIcmsSt
				tmpProPerIcmSt.SetEmpty() // = &NfeProTaxIcmsSt
				tmpProVlrIcmSt.SetEmpty() // = &NfeProVlrImcsSt

				tmpNfeProTaxMvaSt.SetEmpty() // = &NfeProTaxMvaSt

				tmpProPerRedIcmSt.SetEmpty() // = &NfeProTaxRedIcmsSt
				tmpProPerRedIcm.SetEmpty() // = &NfeProTaxRedIcms

				tmpProBasFCPIcmsSt.SetEmpty() // = &tmpProBasFCPIcmsSt
				tmpProVlrFCPIcmsSt.SetEmpty() // = &tmpProVlrFCPIcmsSt
				tmpProTaxFCPIcmsSt.SetEmpty() // = &tmpProTaxFCPIcmsSt

				//IPI
				tmpProBasVlrIpi = 0//val(&det.imposto.IPI.IPITrib.vBC)
				tmpProPerIpi = 0//val(&det.imposto.IPI.IPITrib.pIPI)
				tmpProVlrIpi = 0//val(&det.imposto.IPI.IPITrib.vIPI)		
			EndNEw

			commit
		Else
			&Fim += 1
		Endif

		&Linha += 1
	EndDo
Endif


Sub 'LimpaCampos'
	&ProCod = 0
	&ProGraCod = 0
	&tmpPedVlrUnt.SetEmpty()
	&ProNom = ''
	&tmpProNcmCod = 0
	&tmpProBar = ''
	&tmpProQtdCmpEmb = 0
	&ForProNom = ''
	&tmpNcmCod.SetEmpty()
	&ForProCod.SetEmpty()
	&ProGraRef.SetEmpty()
	&PedQtd.SetEmpty()
	&ForProGraBar.SetEmpty()
EndSub

