Sub 'getProdutoFornecedor'	
	&IsAchou = false
	For Each Order EmpCod, ForCNPJ, ForProCod
		Where EmpCod = &EmpCod
		Where ForCNPJ = &ForCNPJ
		Where ForProCod = &ForProCod
		&ProGraRef = ForErpProRef
		do 'GetProduto'
		Exit
	when none
		For Each Order EmpCod, ProCod, ProForCod
			Where EmpCod = &EmpCod
			Where ProForNumCpfCpnj = &ForCNPJ
			Where ProForProCod = &ForProCod
			&ProGraRef = ProRef
			do 'GetProduto'
			Exit
		EndFor

		if &IsAchou = false
			//Verifica Codigo barras
			if &ForProGraBar <> 'SEM GTIN'
				&ProGraRef = &ForProGraBar //= &det.prod.cEAN
				do 'GetProduto'
			Endif
		Endif

		if &IsAchou = false
			//&ProGraRef = &ForProCod //= &det.prod.cProd
			//do 'GetProduto'
			&ProGraRef = ''
			For Each Order EmpCod, ProCod, ProGraCod
				Where EmpCod = &EmpCod
				Where ProNom = &ForProNom
				&ProNom = ProNomGra
				&ProGraRef = ProGraRef
				&ProCod = ProCod
				&ProGraCod = ProGraCod
				&tmpProQtdCmpEmb = ProQtdCmpEmb
				&tmpProNcmCod =  NcmCod
				&tmpProBar = ProBar

				Exit
			EndFor
		Endif	
	EndFor
EndSub


Sub 'GetProduto'
	&IsAchou = false
	RetornaProdutoReferencia.Call(&EmpCod, &ProGraRef, &ProCod, &ProGraCod, &ProNom, &IsAchou, &ProReqVlr, &ProReqQTd, &ProBarQtd, &ErroMensagem)
	For Each Order EmpCod, ProCod, ProGraCod
		Where EmpCod = &EmpCod
		Where ProCod = &ProCod
		Where ProGraCod = &ProGraCod
		&ProCod = ProCod
		&ProGraCod = ProGraCod
		&ProNom = ProNomGra
		&tmpProQtdCmpEmb = ProQtdCmpEmb
		&tmpProNcmCod =  NcmCod
		&tmpProBar = ProBar
		&ProGraRef = ProGraRef
		&IsAchou = true
		Exit
	EndFor
EndSub
